def load_category_rows(raw_rows):
    loaded = []
    seen_ids = set()

    for raw in raw_rows:
        category_id = raw["id"]
        name = raw["name"].strip()
        parent_id = raw.get("parent_id")
        if parent_id not in seen_ids:
            parent_id = None

        loaded.append(
            {
                "id": category_id,
                "name": name,
                "parent_id": parent_id,
            }
        )
        seen_ids.add(category_id)

    return loaded

