def build_category_paths(rows):
    paths = {}

    for row in rows:
        parent_id = row["parent_id"]
        if parent_id is not None and parent_id in paths:
            paths[row["id"]] = f"{paths[parent_id]}/{row['name']}"
        else:
            paths[row["id"]] = row["name"]

    return paths

