from category_loader import load_category_rows
from category_paths import build_category_paths


def test_loader_normalizes_parent_first_rows():
    rows = load_category_rows(
        [
            {"id": "home", "name": " Home ", "parent_id": None},
            {"id": "lighting", "name": "Lighting", "parent_id": "home"},
        ]
    )

    assert rows == [
        {"id": "home", "name": "Home", "parent_id": None},
        {"id": "lighting", "name": "Lighting", "parent_id": "home"},
    ]


def test_path_builder_handles_parent_before_child():
    rows = [
        {"id": "home", "name": "Home", "parent_id": None},
        {"id": "lighting", "name": "Lighting", "parent_id": "home"},
        {"id": "lamps", "name": "Lamps", "parent_id": "lighting"},
    ]

    assert build_category_paths(rows) == {
        "home": "Home",
        "lighting": "Home/Lighting",
        "lamps": "Home/Lighting/Lamps",
    }


def test_loaded_rows_can_be_used_to_build_paths():
    rows = load_category_rows(
        [
            {"id": "garden", "name": "Garden", "parent_id": None},
            {"id": "tools", "name": "Tools", "parent_id": "garden"},
        ]
    )

    assert build_category_paths(rows)["tools"] == "Garden/Tools"
